namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string InstructorName { get; set; } = "";
    public string InstructorBio { get; set; } = "";
    public string DepartmentId { get; set; } = "";
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public string Id { get; set; } = "";
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9]{6,12}$", ErrorMessage = "Student ID must be 6–12 alphanumeric characters.")]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    public int? CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = "MATH", Name = "Mathematics", Description = "Exploration of numbers, structures, and abstract reasoning." },
            new() { Id = "ENG", Name = "English", Description = "Literature, writing, and critical analysis of texts." },
            new() { Id = "PHYS", Name = "Physics", Description = "Understanding the fundamental laws of the physical universe." }
        };

        _courses = new List<Course>
        {
            new()
            {
                Id = 1, CourseCode = "CS101", Title = "Introduction to Programming",
                Description = "An introductory course covering fundamental programming concepts using Python. Topics include variables, control flow, functions, and basic data structures.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM",
                InstructorName = "Dr. Alice Chen", InstructorBio = "Dr. Chen has over 15 years of experience teaching introductory computer science and has published research on CS education pedagogy.",
                DepartmentId = "CS", IsFeatured = true
            },
            new()
            {
                Id = 2, CourseCode = "CS201", Title = "Data Structures",
                Description = "Study of fundamental data structures including arrays, linked lists, trees, graphs, and hash tables. Emphasis on algorithmic efficiency and implementation.",
                Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM",
                InstructorName = "Dr. Bob Martinez", InstructorBio = "Dr. Martinez specializes in algorithm design and has contributed to open-source data structure libraries.",
                DepartmentId = "CS", IsFeatured = false
            },
            new()
            {
                Id = 3, CourseCode = "CS301", Title = "Algorithms",
                Description = "Advanced study of algorithm design and analysis. Covers divide and conquer, dynamic programming, greedy algorithms, and NP-completeness.",
                Credits = 4, Schedule = "Mon/Wed 1:00–2:15 PM",
                InstructorName = "Dr. Bob Martinez", InstructorBio = "Dr. Martinez specializes in algorithm design and has contributed to open-source data structure libraries.",
                DepartmentId = "CS", IsFeatured = false
            },
            new()
            {
                Id = 4, CourseCode = "MATH101", Title = "Calculus I",
                Description = "Introduction to differential and integral calculus. Topics include limits, derivatives, integrals, and the Fundamental Theorem of Calculus.",
                Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM",
                InstructorName = "Dr. Carol Nguyen", InstructorBio = "Dr. Nguyen is an award-winning mathematics educator with a focus on making calculus accessible to all students.",
                DepartmentId = "MATH", IsFeatured = true
            },
            new()
            {
                Id = 5, CourseCode = "MATH201", Title = "Linear Algebra",
                Description = "Study of vector spaces, linear transformations, matrices, determinants, eigenvalues, and eigenvectors with applications.",
                Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM",
                InstructorName = "Dr. David Kim", InstructorBio = "Dr. Kim researches applied linear algebra and its connections to machine learning and data science.",
                DepartmentId = "MATH", IsFeatured = false
            },
            new()
            {
                Id = 6, CourseCode = "ENG101", Title = "English Composition",
                Description = "Develops skills in academic writing, critical reading, and argumentation. Students produce essays in multiple genres and learn revision strategies.",
                Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:15 PM",
                InstructorName = "Prof. Elena Rivera", InstructorBio = "Prof. Rivera is a published author and has taught composition courses for over a decade.",
                DepartmentId = "ENG", IsFeatured = true
            },
            new()
            {
                Id = 7, CourseCode = "ENG201", Title = "American Literature",
                Description = "Survey of American literature from the colonial period to the present. Examines major authors, movements, and cultural contexts.",
                Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM",
                InstructorName = "Prof. Elena Rivera", InstructorBio = "Prof. Rivera is a published author and has taught composition courses for over a decade.",
                DepartmentId = "ENG", IsFeatured = false
            },
            new()
            {
                Id = 8, CourseCode = "PHYS101", Title = "Physics I",
                Description = "Introduction to classical mechanics covering kinematics, Newton's laws, energy, momentum, rotational motion, and gravitation.",
                Credits = 4, Schedule = "Mon/Wed/Fri 2:00–2:50 PM",
                InstructorName = "Dr. Frank Thompson", InstructorBio = "Dr. Thompson is a physicist with research experience at CERN and a passion for undergraduate education.",
                DepartmentId = "PHYS", IsFeatured = true
            },
            new()
            {
                Id = 9, CourseCode = "PHYS401", Title = "Quantum Mechanics",
                Description = "Introduction to quantum mechanics including wave functions, the Schrödinger equation, quantum states, and measurement theory.",
                Credits = 4, Schedule = "Tue/Thu 3:00–4:15 PM",
                InstructorName = "Dr. Frank Thompson", InstructorBio = "Dr. Thompson is a physicist with research experience at CERN and a passion for undergraduate education.",
                DepartmentId = "PHYS", IsFeatured = false
            }
        };
    }

    public Task<List<Department>> GetDepartmentsAsync()
    {
        return Task.FromResult(_departments.ToList());
    }

    public Task<List<Course>> GetCoursesAsync(string? search, string? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
        {
            query = query.Where(c => c.DepartmentId.Equals(departmentId, StringComparison.OrdinalIgnoreCase));
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            query = query.Where(c =>
                c.Title.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(search, StringComparison.OrdinalIgnoreCase));
        }

        return Task.FromResult(query.ToList());
    }

    public Task<Course?> GetCourseByIdAsync(int id)
    {
        return Task.FromResult(_courses.FirstOrDefault(c => c.Id == id));
    }

    public Task<List<Course>> GetFeaturedCoursesAsync()
    {
        return Task.FromResult(_courses.Where(c => c.IsFeatured).ToList());
    }

    public Task<bool> SubmitEnrollmentRequestAsync(EnrollmentRequest request)
    {
        return Task.FromResult(true);
    }
}

