﻿@page "/"
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="hero">
    <h1>University Course Catalog</h1>
    <p class="lead">Welcome to the university course catalog. Browse our departments, explore courses, and enroll today.</p>
</div>

<h2 class="mb-3">Featured Courses</h2>
<div class="row mb-4">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-3 mb-3">
            <div class="card h-100 featured-card">
                <div class="card-body">
                    <h5 class="card-title">@course.Title</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.CourseCode</h6>
                    <p class="card-text">
                        <span class="badge bg-primary credits-badge">@course.Credits Credits</span>
                    </p>
                    <a href="/courses/@course.Id" class="card-link">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mb-3">Departments</h2>
<div class="row">
    <div class="col-md-8">
        @foreach (var dept in departments)
        {
            <a href="/catalog?department=@dept.Id" class="dept-link">@dept.Name — @dept.Description</a>
        }
    </div>
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override async Task OnInitializedAsync()
    {
        featuredCourses = await CatalogService.GetFeaturedCoursesAsync();
        departments = await CatalogService.GetDepartmentsAsync();
    }
}

