@inject CatalogService CatalogService

@if (course is not null)
{
    <PageTitle>@course.Title</PageTitle>

    <div class="course-detail-header">
        <h1>@course.Title</h1>
        <span class="text-muted me-3">@course.CourseCode</span>
        <span class="badge bg-primary credits-badge">@course.Credits Credits</span>
    </div>

    <p class="lead">@course.Description</p>

    <div class="mb-3">
        <strong>Schedule:</strong> @course.Schedule
    </div>

    <div class="instructor-section">
        <h4>Instructor: @course.InstructorName</h4>
        <p>@course.InstructorBio</p>
    </div>

    <div class="mt-4">
        <a href="/catalog" class="btn btn-outline-secondary">Back to Catalog</a>
    </div>
}
else
{
    <PageTitle>Course Not Found</PageTitle>
    <div class="alert alert-warning">Course not found.</div>
    <a href="/catalog" class="btn btn-outline-secondary">Back to Catalog</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override async Task OnInitializedAsync()
    {
        course = await CatalogService.GetCourseByIdAsync(Id);
    }
}
ENDOFFILE

