     public Task<List<Department>> GetDepartmentsAsync()
     {
         return Task.FromResult(_departments.ToList());
     }

     public Task<List<Course>> GetCoursesAsync(string? search, string? departmentId)
     {
         var query = _courses.AsEnumerable();

         if (!string.IsNullOrWhiteSpace(departmentId))
         {
             query = query.Where(c => c.DepartmentId.Equals(departmentId, StringComparison.OrdinalIgnoreCase));
         }

         if (!string.IsNullOrWhiteSpace(search))
         {
             query = query.Where(c =>
                 c.Title.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                 c.CourseCode.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                 c.Description.Contains(search, StringComparison.OrdinalIgnoreCase));
         }

         return Task.FromResult(query.ToList());
     }

     public Task<Course?> GetCourseByIdAsync(int id)
     {
         return Task.FromResult(_courses.FirstOrDefault(c => c.Id == id));
     }

     public Task<List<Course>> GetFeaturedCoursesAsync()
     {
         return Task.FromResult(_courses.Where(c => c.IsFeatured).ToList());
     }

     public Task<bool> SubmitEnrollmentRequestAsync(EnrollmentRequest request)
     {
         return Task.FromResult(true);
     }
 }

