         <ValidationSummary class="text-danger" />

         <div class="mb-3">
             <label for="fullName" class="form-label">Full Name</label>
             <InputText id="fullName" class="form-control" @bind-Value="Request!.FullName" />
             <ValidationMessage For="() => Request!.FullName" />
         </div>

         <div class="mb-3">
             <label for="studentId" class="form-label">Student ID</label>
             <InputText id="studentId" class="form-control" @bind-Value="Request!.StudentId" />
             <ValidationMessage For="() => Request!.StudentId" />
         </div>

         <div class="mb-3">
             <label for="courseId" class="form-label">Course</label>
             <InputSelect id="courseId" class="form-select" @bind-Value="Request!.CourseId">
                 <option value="">-- Select a course --</option>
                 @foreach (var course in courses)
                 {
                     <option value="@course.Id">@course.CourseCode — @course.Title</option>
                 }
             </InputSelect>
             <ValidationMessage For="() => Request!.CourseId" />
         </div>

         <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
     </EditForm>
 }

 @code {
     [SupplyParameterFromForm]
     private EnrollmentRequest? Request { get; set; }

     protected override void OnInitialized()
     {
         Request ??= new();
     }

     private List<Course> courses = new();
     private bool submitted;

     protected override async Task OnInitializedAsync()
     {
         courses = await CatalogService.GetCoursesAsync(null, null);
     }

     private async Task HandleSubmit()
     {
         await CatalogService.SubmitEnrollmentRequestAsync(Request!);
         submitted = true;
     }
 }

